import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Workflow: Research a Ticker","description":"","frontmatter":{},"headers":[],"relativePath":"workflows/research-ticker.md","filePath":"workflows/research-ticker.md"}'),i={name:"workflows/research-ticker.md"};function r(l,a,o,p,c,h){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="workflow-research-a-ticker" tabindex="-1">Workflow: Research a Ticker <a class="header-anchor" href="#workflow-research-a-ticker" aria-label="Permalink to &quot;Workflow: Research a Ticker&quot;">​</a></h1><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Build a complete picture of a security: fundamentals, financials, price history, ownership, news, events, and peer context.</p><h2 id="complete-step-by-step" tabindex="-1">Complete Step-by-Step <a class="header-anchor" href="#complete-step-by-step" aria-label="Permalink to &quot;Complete Step-by-Step&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>Step 1:  AAPL US DES GO         → Open description screen (fundamentals overview)</span></span>
<span class="line"><span>Step 2:  AAPL US CN GO          → Company news (what&#39;s driving the stock today)</span></span>
<span class="line"><span>Step 3:  AAPL US HP 1Y GO       → One-year price history (OHLCV table)</span></span>
<span class="line"><span>Step 4:  AAPL US GP GO          → Price chart (visual candlestick/line)</span></span>
<span class="line"><span>Step 5:  AAPL US FA GO          → Financial analysis (IS/BS/CF)</span></span>
<span class="line"><span>Step 6:  AAPL US RELS GO        → Related securities (peers, comps)</span></span>
<span class="line"><span>Step 7:  AAPL US OWN GO         → Institutional ownership</span></span>
<span class="line"><span>Step 8:  AAPL US EVT GO         → Corporate events (earnings, dividends, splits)</span></span>
<span class="line"><span>Step 9:  AAPL US MGMT GO        → Management team</span></span>
<span class="line"><span>Step 10: AAPL US DVD GO         → Dividend history</span></span></code></pre></div><h2 id="keyboard-only-path" tabindex="-1">Keyboard-Only Path <a class="header-anchor" href="#keyboard-only-path" aria-label="Permalink to &quot;Keyboard-Only Path&quot;">​</a></h2><ol><li>Type <code>AAPL US DES GO</code> + <strong>Enter</strong></li><li>Press <strong>F2</strong> → MENU shows: HP · GP · CN · OWN · RELS · FA</li><li>Press <strong>Enter</strong> on HP → jumps to Historical Pricing</li><li><strong>Ctrl+B</strong> → back to DES</li><li><strong>Shift+Enter</strong> on CN in next actions → opens CN in new pane</li><li><strong>Alt+Click</strong> any fundamental value → Inspector with lineage</li><li><strong>Ctrl+B</strong> again → return to DES</li></ol><h2 id="multi-pane-research-setup" tabindex="-1">Multi-Pane Research Setup <a class="header-anchor" href="#multi-pane-research-setup" aria-label="Permalink to &quot;Multi-Pane Research Setup&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>Pane 1: AAPL US DES GO</span></span>
<span class="line"><span>Pane 2: AAPL US GP GO      (NP GO to create, then Shift+Enter from DES)</span></span>
<span class="line"><span>Pane 3: AAPL US CN GO      (NP GO again)</span></span>
<span class="line"><span>Pane 4: AAPL US OWN GO     (NP GO)</span></span></code></pre></div><p>Or load the Research preset: <code>WS:RESEARCH GO</code></p><h2 id="related-functions" tabindex="-1">Related Functions <a class="header-anchor" href="#related-functions" aria-label="Permalink to &quot;Related Functions&quot;">​</a></h2><p>DES · HP · GP · GIP · FA · OWN · RELS · CN · DVD · EVT · MGMT · NOTES · RELG · CMPY · SUPP</p><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><ul><li><strong>DES requires security</strong>: Always include market suffix (AAPL US, not just AAPL)</li><li><strong>FA tabs</strong>: Click IS / BS / CF to switch statement types</li><li><strong>OWN is institutional only</strong>: Individual holders not shown in SIM data</li><li><strong>RELS uses sector correlation</strong>: Peers are algorithmically determined, not curated</li></ul>`,14)])])}const S=e(i,[["render",r]]);export{u as __pageData,S as default};
